import { syntaxTree } from '@codemirror/language';
import { Range } from '@codemirror/state';
import { ViewPlugin, Decoration } from '@codemirror/view';
import type { DecorationSet, EditorView, ViewUpdate } from '@codemirror/view';

import {
  stringAnnotation,
  ANNOTATION_DELETE_STATEMENT,
  pastingMode,
} from '../editor-state-configs/editor-config.js';
import { filterStatementDeleteWidget } from '../FilterField.sty.js';
import { useErrorLogsStore } from '../hooks/useErrorLogsStore.js';
import { cleanUpInput } from '../utils/delete-widget-cleanup.js';
import { NEEDS_ESCAPING_REGEX } from '../utils/escape-suggestion.js';
import { getStatementStatus } from '../utils/get-statement-status.js';
import { DeleteStatementWidget } from '../widgets/DeleteStatementWidget.js';

const needsEscapingRegex = new RegExp(NEEDS_ESCAPING_REGEX);

/**
 * Create a range set with decorations for all the filter statements.
 * @internal
 */
export function createFilterStatementDeleteWidgets(view: EditorView) {
  const widgets: Range<Decoration>[] = [];

  const pastingStateField = view?.state.field(pastingMode, false);

  // Only suppress delete widgets when pasted content contains special
  // characters (complex content). Non-complex pasted content (e.g. plain
  // text without reserved characters) should show delete widgets as usual.
  const pastedContentHasSpecialChars =
    pastingStateField?.pastingInProgress &&
    pastingStateField.range !== undefined &&
    needsEscapingRegex.test(
      view.state.doc.sliceString(
        pastingStateField.range.from,
        pastingStateField.range.to,
      ),
    );

  const pastedRange = pastedContentHasSpecialChars
    ? pastingStateField.range
    : undefined;

  for (const { from, to } of view.visibleRanges) {
    syntaxTree(view.state).iterate({
      from,
      to,
      enter: (node) => {
        if (node.name === 'FilterStatement') {
          const { from, to } = node;

          // Skip the delete widget for statements that overlap or touch the
          // pasted range — pasted content with special characters should not
          // be deletable via the statement delete button.
          if (pastedRange && pastedRange.from <= to && pastedRange.to >= from) {
            return false;
          }

          const statementType = getStatementStatus(
            node.node.cursor(),
            view.state.doc.toString(),
          );

          const deleteStatementWidget = Decoration.widget({
            widget: new DeleteStatementWidget(
              from,
              to,
              statementType === 'incomplete',
            ),
          });
          widgets.push(deleteStatementWidget.range(to));

          return false;
        }
      },
    });
  }

  return Decoration.set(widgets);
}

/**
 * View plugin to wrap all filter statements in spans.
 * @internal
 */
export const FilterStatementDeleteWidgetPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createFilterStatementDeleteWidgets(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createFilterStatementDeleteWidgets(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
    eventHandlers: {
      mousedown: (event, view) => {
        const target = event.target as HTMLElement;
        if (
          target.nodeName === 'BUTTON' &&
          target.parentElement &&
          target.parentElement.classList.contains(filterStatementDeleteWidget)
        ) {
          event.preventDefault();

          // We are not in a react context here, have to access the zustand store via the store API.
          const setAction = useErrorLogsStore.getState().setAction;

          const { from: dataFrom, to: dataTo } = target.dataset;
          const parsedFrom = parseInt(dataFrom ?? '0');
          const parsedTo = parseInt(dataTo ?? '0');

          const currentValue = view.state.doc.toString();

          // Use the cleanup function to determine the proper range to delete
          const adjustedRange = cleanUpInput(view.state, {
            from: parsedFrom,
            to: parsedTo,
          });

          const { from, to } = adjustedRange;

          setAction({
            type: 'deleteStatement',
            data: {
              value: currentValue,
              range: { from, to },
              newCursorPos: from,
            },
          });

          view.dispatch({
            changes: {
              from,
              to,
              insert: '',
            },
            annotations: stringAnnotation.of(ANNOTATION_DELETE_STATEMENT),
            selection: { anchor: from },
          });
        }
      },
    },
  },
);
